<?php $adminTitle='Business Learner Progress';require_once __DIR__.'/../includes/business-admin-header.php';$type=(string)($_GET['type']??'All');$sql='SELECT p.*,l.full_name,l.email,c.title course_title,c.learner_type,bl.title lesson_title,a.title activity_title FROM business_progress p JOIN learners l ON l.id=p.learner_id JOIN business_courses c ON c.id=p.course_id LEFT JOIN business_lessons bl ON bl.id=p.lesson_id LEFT JOIN business_activities a ON a.id=p.activity_id';$params=[];if(in_array($type,['Business','General'],true)){$sql.=' WHERE c.learner_type=?';$params[]=$type;}$sql.=' ORDER BY p.updated_at DESC';$s=$pdo->prepare($sql);$s->execute($params);$rows=$s->fetchAll();?>
<div class="admin-top"><div><p class="eyebrow">Business AI Academy</p><h1>Learner Progress</h1></div><form><select class="form-select" name="type" onchange="this.form.submit()"><option>All</option><option <?=$type==='Business'?'selected':''?>>Business</option><option <?=$type==='General'?'selected':''?>>General</option></select></form></div><div class="glass-card table-responsive"><table class="table table-dark"><tr><th>Learner</th><th>Type</th><th>Program / Content</th><th>Score</th><th>Status</th><th>Updated</th></tr><?php foreach($rows as $r):?><tr><td><strong><?=e($r['full_name'])?></strong><small class="d-block text-secondary"><?=e($r['email'])?></small></td><td><?=e($r['learner_type'])?></td><td><?=e($r['course_title'])?><small class="d-block text-secondary"><?=e($r['activity_title']??$r['lesson_title']??'Course work')?></small></td><td><?=isset($r['score'])?(int)$r['score'].'%':'—'?></td><td><?=e($r['status'])?></td><td><?=e(date('M j, Y',strtotime($r['updated_at'])))?></td></tr><?php endforeach?></table></div>
<?php require_once __DIR__.'/../includes/business-admin-footer.php';?>
